function shiftClock(value,minutes){var m=String(value).match(/^(\d{2}):(\d{2})$/);if(!m)return value;var total=(+m[1])*60+(+m[2])+minutes;total=(total+1440)%1440;return String(Math.floor(total/60)).padStart(2,'0')+':'+String(total%60).padStart(2,'0')}
