function standings(){var arr=[],plan=activePlan();for(var i=1;i<=state.teamCount;i++)arr.push({id:i,name:teamName(i),gp:0,w:0,l:0,p:0,bp:0,ga:0,d:0});if(!plan)return arr;plan.matches.forEach(function(m,idx){var s=state.scores[scoreKey(idx)];if(!s||s[0]===''||s[1]===''||+s[0]===+s[1])return;var a=+s[0],b=+s[1];m.a.forEach(function(id){var t=arr[id-1];t.gp++;t.bp+=a;t.ga+=b;if(a>b){t.w++;t.p++}else t.l++});m.b.forEach(function(id){var t=arr[id-1];t.gp++;t.bp+=b;t.ga+=a;if(b>a){t.w++;t.p++}else t.l++})});arr.forEach(function(t){t.d=t.bp-t.ga});arr.sort(function(a,b){return b.p-a.p||b.d-a.d||a.id-b.id});var rank=0,last=null;arr.forEach(function(t,i){if(!last||t.p!==last.p||t.d!==last.d)rank=i+1;t.rank=rank;last=t});return arr}
function renderTable(){var rows=standings(),hide=isViewerMode()&&state.finalRound&&state.hideFinalQualifiers!==false&&state.teamCount>=8,h='';var hint=qs('#tableHint');if(hide){if(hint)hint.textContent='Die acht qualifizierten Teams werden öffentlich ohne genaue Vorrundenplatzierung angezeigt.';var q=rows.slice(0,8).slice().sort(function(a,b){return a.name.localeCompare(b.name,'de')});q.forEach(function(t){h+='<tr class="qualified-row"><td><b>✓</b></td><td>'+esc(t.name)+'<small class="qualified-label">Qualifiziert für die Finalrunde</small></td><td class="muted-stat">—</td><td class="muted-stat">—</td><td class="muted-stat">—</td><td class="muted-stat">—</td><td class="muted-stat">—</td><td class="muted-stat">—</td><td class="muted-stat">—</td></tr>'});rows.slice(8).forEach(function(t){h+='<tr><td><b>'+t.rank+'</b></td><td>'+esc(t.name)+'</td><td>'+t.gp+'</td><td>'+t.w+'</td><td>'+t.l+'</td><td><b>'+t.p+'</b></td><td>'+t.bp+'</td><td>'+t.ga+'</td><td>'+t.d+'</td></tr>'})}else{if(hint)hint.textContent='Gleiche Punkte und gleiche Differenz ergeben denselben Platz.';h=rows.map(function(t){var c=t.rank===1?'rank1':t.rank===2?'rank2':t.rank===3?'rank3':'';return '<tr class="'+c+'"><td><b>'+t.rank+'</b></td><td>'+esc(t.name)+'</td><td>'+t.gp+'</td><td>'+t.w+'</td><td>'+t.l+'</td><td><b>'+t.p+'</b></td><td>'+t.bp+'</td><td>'+t.ga+'</td><td>'+t.d+'</td></tr>'}).join('')}qs('#standings').innerHTML=h}
function stats(){var n=state.teamCount,p=activePlan(),x=[];for(var i=1;i<=n;i++)x.push({id:i,partners:[],opps:[],fields:{},fieldTypes:{},rounds:[]});if(!p)return x;p.matches.forEach(function(m){m.a.forEach(function(id){m.a.forEach(function(v){if(v!==id)x[id-1].partners.push(v)});x[id-1].opps=x[id-1].opps.concat(m.b);x[id-1].rounds.push(m.round);x[id-1].fields[m.field]=(x[id-1].fields[m.field]||0)+1;var ft=m.fieldType||(p.fieldTypes&&p.fieldTypes[m.slot])||(/sand/i.test(m.field)?'Sand':/halle/i.test(m.field)?'Halle':/rasen/i.test(m.field)?'Rasen':'Sonstiges');x[id-1].fieldTypes[ft]=(x[id-1].fieldTypes[ft]||0)+1});m.b.forEach(function(id){m.b.forEach(function(v){if(v!==id)x[id-1].partners.push(v)});x[id-1].opps=x[id-1].opps.concat(m.a);x[id-1].rounds.push(m.round);x[id-1].fields[m.field]=(x[id-1].fields[m.field]||0)+1;var ft=m.fieldType||(p.fieldTypes&&p.fieldTypes[m.slot])||(/sand/i.test(m.field)?'Sand':/halle/i.test(m.field)?'Halle':/rasen/i.test(m.field)?'Rasen':'Sonstiges');x[id-1].fieldTypes[ft]=(x[id-1].fieldTypes[ft]||0)+1})});return x}
function renderPartners(){var h='';stats().forEach(function(t){var oc={},pc={};t.opps.forEach(function(o){oc[o]=(oc[o]||0)+1});t.partners.forEach(function(o){pc[o]=(pc[o]||0)+1});var repeats=Object.keys(pc).filter(function(o){return pc[o]>1});h+='<div class="partner-card"><b>'+teamName(t.id)+'</b><div class="overview-label">Partner:</div><div class="chips">'+Object.keys(pc).map(function(o){return '<span class="chip '+(pc[o]>1?'repeat':'')+'">'+teamName(+o)+(pc[o]>1?' × '+pc[o]:'')+'</span>'}).join('')+'</div><div class="repeat-note '+(repeats.length?'bad':'ok')+'">'+(repeats.length?'⚠ Wiederholt: '+repeats.map(function(o){return teamName(+o)+' × '+pc[o]}).join(', '):'✓ kein Partner mehrfach')+'</div><div class="overview-label">Gegner:</div><div class="chips">'+Object.keys(oc).map(function(o){return '<span class="chip">'+teamName(+o)+' × '+oc[o]+'</span>'}).join('')+'</div></div>'});qs('#partners').innerHTML=h}
function renderFairness(){var h='',plan=activePlan(),summary=tournamentFairnessScore();if(summary){var cls=summary.score>=90?'perfect':summary.score>=75?'near':'poor',court=summary.court,detail=court?court.details.map(function(d){return '<span class="chip court-type-chip">'+esc(d.type)+': '+d.min+(d.max!==d.min?'–'+d.max:'')+' je Team</span>'}).join(''):'';qs('#fairnessSummary').innerHTML='<div class="fairness-score-card '+cls+'"><div class="score-ring"><b>'+summary.score+'</b><span>%</span></div><div><h3>Fairness-Score</h3><p>'+(summary.issues.length?esc(summary.issues.join(' · ')):'Alle zentralen Fairnesskriterien sind erfüllt.')+'</p><div class="chips">'+detail+'</div></div></div>'}else qs('#fairnessSummary').innerHTML='';stats().forEach(function(t){var up=new Set(t.partners).size,uo=new Set(t.opps).size,maxO=0,c={};t.opps.forEach(function(o){c[o]=(c[o]||0)+1;maxO=Math.max(maxO,c[o])});var rs=t.rounds.slice().sort(function(a,b){return a-b}),maxSeries=rs.length?1:0,cur=1,maxPause=0;for(var i=1;i<rs.length;i++){if(rs[i]===rs[i-1]+1){cur++;maxSeries=Math.max(maxSeries,cur)}else{maxPause=Math.max(maxPause,rs[i]-rs[i-1]-1);cur=1}}var okGames=rs.length===plan.gamesPerTeam,partnerRepeats=t.partners.length-up,fieldChips=Object.keys(t.fieldTypes).sort().map(function(f){return '<span class="chip court-type-chip">'+esc(f)+': '+t.fieldTypes[f]+'</span>'}).join('');h+='<div class="fair-card"><b>'+teamName(t.id)+'</b><div class="chips"><span class="chip">Spiele '+rs.length+'/'+plan.gamesPerTeam+'</span><span class="chip">versch. Partner '+up+'</span><span class="chip">Partnerwiederholungen '+partnerRepeats+'</span><span class="chip">Gegner '+uo+'</span><span class="chip">max. Gegnerhäufigkeit '+maxO+'</span>'+fieldChips+'<span class="chip">längste Serie '+maxSeries+'</span><span class="chip">längste Pause '+maxPause+'</span><span class="'+(okGames?'ok':'bad')+'">'+(okGames?'✓ gleiche Spielanzahl':'⚠ falsche Spielanzahl')+'</span></div></div>'});qs('#fairness').innerHTML=h}
